{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires calculating the effective Rydberg energy from the 1s exciton binding energy and then applying the Rydberg formula for n=3, paying close attention to the sign convention of binding energy.",
  "helpers": [
    {
      "label": "helper_1",
      "instructions": "Calculate the effective Rydberg energy (Ry*) using the given 1s exciton peak energy and the band gap. Note that the exciton peak energy represents the energy of the state relative to the ground state, and the binding energy is the difference between the band gap and the peak energy. Use the relation E_b = Ry* / (n^2) for n=1 to find Ry*."
    },
    {
      "label": "helper_2",
      "instructions": "Using the effective Rydberg energy (Ry*) found in the first step, calculate the energy level for the n=3 state. Apply the formula E_n = -Ry* / (n^2) to determine the energy relative to the conduction band edge, ensuring the sign convention reflects the bound state energy."
    }
  ],
  "synthesis_brief": "Combine the results by taking the calculated energy for n=3 from helper 2. Ensure the final value is the specific energy level requested, maintaining the correct sign as per the Rydberg formula for bound states."
}

